import React from 'react';
import { Outlet, Link, Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const Icons = {
  Home: ({active}) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active?"#003366":"#999"} strokeWidth="2"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>,
  Task: ({active}) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active?"#003366":"#999"} strokeWidth="2"><path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
};

const StaffLayout = () => {
  const { user, logout } = useAuth();
  const { staffList } = useData();
  const location = useLocation();

  if (!user) return <Navigate to="/" />;

  // Lấy dữ liệu mới nhất (Roles, UBI) từ context thay vì user session cũ
  const currentUserInfo = staffList.find(s => s.id === user.id) || user;

  const isActive = (path) => location.pathname === path;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', background: '#f0f2f5' }}>
      
      {/* Header Staff */}
      <header style={{ background: '#fff', padding: '15px 20px', borderBottom: '1px solid #e0e0e0', boxShadow: '0 1px 3px rgba(0,0,0,0.05)' }}>
         <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
                <h2 style={{ margin: 0, color: '#003366', fontSize: '1.2rem' }}>Chào, {currentUserInfo.name}</h2>
                
                {/* Hiển thị Functional Roles */}
                <div style={{ display: 'flex', gap: '5px', marginTop: '6px', flexWrap: 'wrap' }}>
                    {currentUserInfo.positions && currentUserInfo.positions.length > 0 ? (
                        currentUserInfo.positions.map(p => (
                            <span key={p} style={{ background: '#003366', color: 'white', padding: '2px 8px', borderRadius: '4px', fontSize: '0.7rem', fontWeight: '500' }}>{p}</span>
                        ))
                    ) : <span style={{fontSize: '0.7rem', color: '#999', fontStyle: 'italic'}}>Chưa phân công vị trí</span>}
                </div>
            </div>
            <button onClick={logout} style={{ border: '1px solid #ddd', background: 'transparent', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer', fontSize: '0.8rem' }}>Đăng xuất</button>
         </div>

         {/* Thẻ hiển thị UBI - Remuneration */}
         <div style={{ marginTop: '15px', padding: '12px', background: 'linear-gradient(to right, #e6f7ff, #ffffff)', borderRadius: '8px', border: '1px solid #bae7ff', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={{display: 'flex', flexDirection: 'column'}}>
                <span style={{ fontSize: '0.75rem', color: '#0050b3', textTransform: 'uppercase' }}>Thu nhập định mức (UBI)</span>
                <span style={{ fontSize: '0.7rem', color: '#666' }}>Tỷ lệ hưởng: <strong>{currentUserInfo.ubiPercentage || 100}%</strong></span>
            </div>
            <strong style={{ color: '#003366', fontSize: '1.2rem' }}>
                {((currentUserInfo.baseUBI || 0) * (currentUserInfo.ubiPercentage || 100) / 100).toLocaleString()} <span style={{fontSize: '0.8rem'}}>đ</span>
            </strong>
         </div>
      </header>

      {/* Main Content */}
      <main style={{ flex: 1, padding: '15px', paddingBottom: '80px' }}>
        <Outlet />
      </main>

      {/* Bottom Nav for Mobile */}
      <nav style={{ 
        position: 'fixed', bottom: 0, left: 0, right: 0, background: 'white', 
        borderTop: '1px solid #ddd', display: 'flex', justifyContent: 'space-around', padding: '10px 0',
        zIndex: 1000
      }}>
        <Link to="/staff/my-tasks" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', textDecoration: 'none', color: isActive('/staff/my-tasks') ? '#003366' : '#999' }}>
            <Icons.Task active={isActive('/staff/my-tasks')} />
            <span style={{ fontSize: '0.7rem', marginTop: '4px' }}>Nhiệm vụ</span>
        </Link>
        <Link to="/staff/performance" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', textDecoration: 'none', color: isActive('/staff/performance') ? '#003366' : '#999' }}>
            <Icons.Home active={isActive('/staff/performance')} />
            <span style={{ fontSize: '0.7rem', marginTop: '4px' }}>Hiệu suất</span>
        </Link>
      </nav>
    </div>
  );
};

export default StaffLayout;
